import React, { useState } from 'react';

function ShippingCalculator() {
  const [weight, setWeight] = useState('');
  const [itemType, setItemType] = useState('Hàng thường');
  const [totalCost, setTotalCost] = useState(0);
  const [showDiscount, setShowDiscount] = useState(false);

  const calculateShipping = () => {
    const kg = parseFloat(weight);
    if (isNaN(kg) || kg <= 0) {
      setTotalCost(0);
      setShowDiscount(false);
      return;
    }

    let rate = 0;
    switch (itemType) {
      case 'Hàng thường':
        rate = 260000;
        break;
      case 'Mỹ phẩm':
        rate = 300000;
        break;
      case 'Điện tử':
        // For electronics, user is advised to contact for quote
        setTotalCost('Liên hệ báo giá');
        setShowDiscount(false);
        return;
      default:
        rate = 260000;
    }

    let cost = kg * rate;
    if (kg > 5) {
      cost = kg * 250000; // Apply discount for > 5kg
      setShowDiscount(true);
    } else {
      setShowDiscount(false);
    }

    setTotalCost(cost.toLocaleString('vi-VN') + ' VNĐ');
  };

  return (
    <section className="bg-gray-50 py-16 px-4 md:px-0">
      <div className="container mx-auto text-center">
        <h2 className="text-4xl font-extrabold text-navy">Bảng tính cước nhanh</h2>
        <p className="mt-4 text-lg text-gray-700">Ước tính chi phí vận chuyển của bạn.</p>

        <div className="mt-10 bg-white p-8 rounded-lg shadow-xl max-w-lg mx-auto">
          <div className="mb-6 text-left">
            <label htmlFor="weight" className="block text-gray-800 text-lg font-semibold mb-2">Cân nặng (kg):</label>
            <input
              type="number"
              id="weight"
              className="w-full p-3 border border-gray-300 rounded-md focus:ring-2 focus:ring-orange focus:border-transparent"
              placeholder="Nhập cân nặng của kiện hàng"
              value={weight}
              onChange={(e) => setWeight(e.target.value)}
            />
          </div>

          <div className="mb-8 text-left">
            <label htmlFor="itemType" className="block text-gray-800 text-lg font-semibold mb-2">Loại hàng:</label>
            <select
              id="itemType"
              className="w-full p-3 border border-gray-300 rounded-md focus:ring-2 focus:ring-orange focus:border-transparent bg-white"
              value={itemType}
              onChange={(e) => setItemType(e.target.value)}
            >
              <option value="Hàng thường">Hàng thường (Quần áo, giày dép)</option>
              <option value="Mỹ phẩm">Mỹ phẩm, Nước hoa, Túi xách</option>
              <option value="Điện tử">Điện tử cao cấp (Laptop, iPhone)</option>
            </select>
          </div>

          <button
            onClick={calculateShipping}
            className="w-full bg-orange hover:bg-yellow-600 text-white font-bold py-3 px-6 rounded-full text-xl shadow-md transition-colors"
          >
            Tính cước
          </button>

          {totalCost !== 0 && ( // Display result only when calculated
            <div className="mt-8 p-4 bg-orange-100 border-l-4 border-orange-500 text-orange-800 rounded-md">
              <p className="text-lg font-semibold">Tổng tiền ước tính: <span className="text-2xl font-bold text-navy">{totalCost}</span></p>
              {showDiscount && (
                <p className="mt-2 text-md text-orange-700">🎉 Giảm ngay xuống 250.000đ/kg cho kiện hàng trên 5kg!</p>
              )}
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

export default ShippingCalculator;
